		"viz_lxPtOTuo": {
			"containerOptions": {},
			"context": {},
			"options": {
				"src": " data:image/png;base64,"
			},
			"showLastUpdated": false,
			"showProgressBar": false,
			"type": "splunk.image"
		},
		"viz_pie_category": {
			"dataSources": {
				"primary": "ds_chart_category"
			},
			"options": {
				"seriesColors": [
					"#0A60FF",
					"#3D851C",
					"#0A60FF",
