	"dataSources": {
		"ds_chart_category": {
			"name": "Chart Products by Category",
			"options": {
				"query": "| savedsearch \"SCAN - Product Catalog - By Category\" | fields category total | rename total as Count"
			},
			"type": "ds.search"
		},
		"ds_chart_status": {
			"name": "Chart Products by Status",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| eval _r=1 | table _r active deprecated coming_soon | rename active as Active, deprecated as Deprecated, coming_soon as \"Under Development\" | untable _r Status Count | fields Status Count"
			},
			"type": "ds.chain"
		},
		"ds_chart_support": {
			"name": "Chart Support Level",
			"options": {
				"query": "| rest splunk_server=local /servicesNS/-/-/configs/conf-products | fields support_level | eval Support=case(support_level==\"cisco_supported\",\"Cisco\",support_level==\"splunk_supported\",\"Splunk\",support_level==\"developer_supported\",\"Developer\",support_level==\"community_supported\",\"Community\",1==1,\"Not Supported\") | stats count as Count by Support | sort - Count"
			},
			"type": "ds.search"
		},
		"ds_cisco_compliance": {
			"name": "Table Cisco Compliance",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false type IN (\"app\",\"addon\") | eval validation_status=case(passed_validation==\"true\" AND appinspect_passed==\"true\",\"✅ Fully Validated\",passed_validation==\"true\",\"✅ Passed Validation\",appinspect_passed==\"true\",\"⚠️ AppInspect Only\",1==1,\"❌ Not Validated\") | eval compliance=mvappend(if(fedramp_validation==\"yes\",\"FedRAMP\",null()),if(fips_compatibility==\"yes\",\"FIPS\",null())) | table title type support validation_status compliance app_version | sort 0 validation_status title"
			},
			"type": "ds.chain"
		},
		"ds_cisco_freshness": {
			"name": "Chart Cisco App Freshness",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false type IN (\"app\",\"addon\") | eval days=round((now()-updated_time)/86400) | eval health=case(days<=180,\"🟢 Fresh\",days<=365,\"🟡 Current\",days<=730,\"🟠 Aging\",1==1,\"🔴 Stale\") | stats count by health | sort - count"
			},
			"type": "ds.chain"
		},
		"ds_cisco_platform": {
			"name": "Chart Cisco Platform Compatibility",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false type IN (\"app\",\"addon\") | eval platform=case(like(product_compatibility,\"%Cloud%\") AND like(product_compatibility,\"%Enterprise%\"),\"Cloud + Enterprise\",like(product_compatibility,\"%Cloud%\"),\"Cloud Only\",like(product_compatibility,\"%Enterprise%\"),\"Enterprise Only\",1==1,\"Unknown\") | stats count by platform"
			},
			"type": "ds.chain"
		},
		"ds_cisco_splunkbase": {
			"name": "Cisco Splunkbase Ecosystem",
			"options": {
				"query": "| savedsearch \"SCAN - Cisco Splunkbase Ecosystem\"",
				"queryParameters": {
					"earliest": "-15m",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_cisco_top_downloads": {
			"name": "Chart Cisco Top Downloads",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false type IN (\"app\",\"addon\") | eval downloads=tonumber(download_count) | sort - downloads | head 10 | fields title downloads | rename title as App, downloads as Downloads"
			},
			"type": "ds.chain"
		},
		"ds_cisco_version": {
			"name": "Table Cisco Version Tracker",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false | eval days=round((now()-updated_time)/86400) | eval staleness=case(days<=90,\"🟢 Fresh\",days<=365,\"🟡 Current\",days<=730,\"🟠 Aging\",1==1,\"🔴 Stale\") | eval updated_date=strftime(updated_time,\"%Y-%m-%d\") | table title type support app_version days staleness updated_date | sort - days | head 30"
			},
			"type": "ds.chain"
		},
		"ds_ecosystem_summary": {
			"name": "Ecosystem Summary",
			"options": {
				"query": "| savedsearch \"SCAN - Ecosystem Summary\"",
				"queryParameters": {
					"earliest": "-15m",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_kpi_active": {
			"name": "KPI Active Products",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields active | rename active as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_addon_families": {
			"name": "KPI Add-on Families",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields addon_families | rename addon_families as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_alert_actions": {
			"name": "KPI Alert Actions",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields products_with_alert_action | rename products_with_alert_action as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_cisco_archived": {
			"name": "KPI Cisco Archived Apps",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=true | stats count as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_cisco_downloads": {
			"name": "KPI Cisco Total Downloads",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false | eval dl=tonumber(download_count) | stats sum(dl) as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_cisco_live": {
			"name": "KPI Cisco Live Apps",
			"options": {
				"extend": "ds_cisco_splunkbase",
				"query": "| search is_archived=false type IN (\"app\",\"addon\") | stats count as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_deprecated": {
			"name": "KPI Deprecated",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields deprecated | rename deprecated as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_legacy": {
			"name": "KPI Legacy Apps",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields total_legacy_apps | rename total_legacy_apps as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_soar": {
			"name": "KPI SOAR-Enabled",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields products_with_soar | rename products_with_soar as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_sourcetypes": {
			"name": "KPI Sourcetypes",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields total_sourcetypes | rename total_sourcetypes as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_total_products": {
			"name": "KPI Total Products",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields total_products | rename total_products as total"
			},
			"type": "ds.chain"
		},
		"ds_kpi_viz_apps": {
			"name": "KPI Viz Apps",
			"options": {
				"extend": "ds_ecosystem_summary",
				"query": "| fields products_with_viz_app | rename products_with_viz_app as total"
			},
			"type": "ds.chain"
		},
		"ds_magic6_app_choices": {
			"name": "Magic Eight App Choices",
			"options": {
				"query": "| rest splunk_server=local /services/apps/local f=title f=core | where core=0 | rename title as label | eval value=label | fields label value | dedup label | sort label"
			},
			"type": "ds.search"
		},
		"ds_magic6_audit": {
			"name": "Magic Eight Audit",
			"options": {
				"query": "| savedsearch \"SCAN - Magic Eight Audit\" scope=\"$m6_scope$\""
			},
			"type": "ds.search"
		},
		"ds_magic6_chart_category": {
			"name": "Chart Magic Eight by App",
			"options": {
				"extend": "ds_magic6_filtered",
				"query": "| stats avg(magic_eight_count) as avg_score by \"Defining App(s)\" | eval avg_score=round(avg_score,1) | rename avg_score as \"Avg Settings\", \"Defining App(s)\" as App | sort - \"Avg Settings\""
			},
			"type": "ds.chain"
		},
		"ds_magic6_chart_grade": {
			"name": "Chart Magic Eight Grade Distribution",
			"options": {
				"extend": "ds_magic6_filtered",
				"query": "| stats dc(Stanza) as Count by grade | rename grade as Grade"
			},
			"type": "ds.chain"
		},
		"ds_magic6_filtered": {
			"name": "Magic Eight Filtered",
			"options": {
				"extend": "ds_magic6_audit",
				"query": "| where \"$m6_app$\"=\"*\" OR 'Defining App(s)'=\"$m6_app$\""
			},
			"type": "ds.chain"
		},
		"ds_magic6_kpi_complete": {
			"name": "KPI Magic Eight Complete",
			"options": {
				"extend": "ds_magic6_filtered",
				"query": "| search grade=\"Complete\" | stats dc(Stanza) as total"
			},
			"type": "ds.chain"
		},
		"ds_magic6_kpi_none": {
			"name": "KPI Magic Eight None",
			"options": {
				"extend": "ds_magic6_filtered",
				"query": "| search grade=\"None\" | stats dc(Stanza) as total"
			},
			"type": "ds.chain"
		},
		"ds_magic6_kpi_partial": {
			"name": "KPI Magic Eight Partial",
			"options": {
				"extend": "ds_magic6_filtered",
				"query": "| search grade=\"Partial\" OR grade=\"Minimal\" | stats dc(Stanza) as total"
			},
			"type": "ds.chain"
		},
		"ds_product_version_gap": {
			"name": "Add-ons WITHOUT Version Support",
			"options": {
				"query": "| savedsearch \"SCAN - Products WITHOUT Version Support\""
			},
			"type": "ds.search"
		},
		"ds_product_version_kpi": {
			"name": "KPI Compatible Add-ons",
			"options": {
				"extend": "ds_product_version_support",
				"query": "| where supports_$min_splunk_ver$=\"✅ YES\" | stats count as total"
			},
			"type": "ds.chain"
		},
		"ds_product_version_support": {
			"name": "Add-on Version Support Matrix",
			"options": {
				"query": "| savedsearch \"SCAN - Product Version Support Matrix\""
			},
			"type": "ds.search"
		},
		"ds_table_addon_family": {
			"name": "Table Add-on Families",
			"options": {
				"query": "| savedsearch \"SCAN - Product Catalog - By Add-on Family\""
			},
			"type": "ds.search"
		},
		"ds_table_installed": {
			"name": "Table Installed Cisco Estate",
			"options": {
				"query": "| savedsearch \"SCAN - Installed Apps vs Catalog\""
			},
			"type": "ds.search"
		},
		"ds_table_migration": {
			"name": "Table Migration Map",
			"options": {
				"query": "| savedsearch \"SCAN - Deprecated Migration Map\""
			},
			"type": "ds.search"
		},
		"ds_table_quality": {
			"name": "Table Data Quality Audit",
			"options": {
				"query": "| savedsearch \"SCAN - Data Quality - Missing Fields Audit\""
			},
			"type": "ds.search"
		},
		"ds_table_soar": {
			"name": "Table SOAR Inventory",
			"options": {
				"query": "| savedsearch \"SCAN - SOAR Connector Inventory\""
			},
			"type": "ds.search"
		}
	},
